import React from 'react';
import { Link } from 'react-router-dom';

function Services() {
  // 9 सर्विसेस का डेटा + उनके स्पेसिफिक फोटोज
  const serviceData = [
    { id: 1, title: "Web Development", icon: "fas fa-code", color: "#0d6efd", img: "https://images.unsplash.com", desc: "Building high-speed, futuristic websites that convert visitors into loyal customers." },
    { id: 2, title: "UI/UX Design", icon: "fas fa-layer-group", color: "#dc3545", img: "https://images.unsplash.com", desc: "Pixel-perfect designs focused on user psychology and modern digital aesthetics." },
    { id: 3, title: "App Development", icon: "fas fa-mobile-alt", color: "#198754", img: "https://images.unsplash.com", desc: "Powerful native and cross-platform apps with seamless and smooth user experiences." },
    { id: 4, title: "Assignment Support", icon: "fas fa-book-reader", color: "#ffc107", img: "https://images.unsplash.com", desc: "Expert academic guidance to help you excel in your technical projects and finals." },
    { id: 5, title: "PPT Design", icon: "fas fa-file-powerpoint", color: "#0dcaf0", img: "https://images.unsplash.com", desc: "High-impact visual storytelling that makes your presentations truly unforgettable." },
    { id: 6, title: "Report Writing", icon: "fas fa-file-signature", color: "#6c757d", img: "https://images.unsplash.com", desc: "Professional, data-driven technical reports and structured business documentation." },
    { id: 7, title: "Digital Marketing", icon: "fas fa-bullhorn", color: "#343a40", img: "https://images.unsplash.com", desc: "Strategic growth campaigns to enhance your online presence and market reach." },
    { id: 8, title: "Content Writing", icon: "fas fa-pen-nib", color: "#0d6efd", img: "https://images.unsplash.com", desc: "Engaging and SEO-optimized content that speaks your brand's unique voice." },
    { id: 9, title: "SEO Optimization", icon: "fas fa-search-plus", color: "#20c997", img: "https://images.unsplash.com", desc: "Improve your search engine rankings and attract organic traffic with ease." }
  ];

  return (
    <div className="services-page py-5" style={{ backgroundColor: '#f4f7f6' }}>
      <div className="container">
        
        {/* Modern Header */}
        <div className="text-center mb-5">
          <h1 className="fw-bold display-4 mb-2">My Premium <span style={{ color: '#0d6efd' }}>Services</span></h1>
          <p className="text-muted fs-5">World-class solutions for your digital and academic success in 2026.</p>
          <div className="mx-auto" style={{ width: '60px', height: '5px', backgroundColor: '#0d6efd', borderRadius: '50px' }}></div>
        </div>

        {/* 9 Professional Cards */}
        <div className="row g-4">
          {serviceData.map((service) => (
            <div className="col-lg-4 col-md-6" key={service.id}>
              <div className="card h-100 border-0 shadow-lg rounded-4 overflow-hidden service-card">
                
                {/* Photo Section with Overlay Icon */}
                <div className="position-relative overflow-hidden" style={{ height: '220px' }}>
                  <img src={service.img} alt={service.title} className="w-100 h-100 img-zoom" style={{ objectFit: 'cover' }} />
                  <div className="card-img-overlay d-flex align-items-start justify-content-end">
                    <span className="badge p-2 px-3 rounded-pill shadow-sm" style={{ backgroundColor: service.color, color: 'white' }}>
                      <i className={service.icon}></i> 0{service.id}
                    </span>
                  </div>
                </div>

                {/* Text Section */}
                <div className="card-body p-4 text-center bg-white">
                  <h4 className="fw-bold mb-3" style={{ color: '#2c3e50' }}>{service.title}</h4>
                  <p className="text-muted small mb-4 px-2" style={{ minHeight: '50px' }}>{service.desc}</p>
                  
                  <Link to="/register" className="btn btn-outline-dark w-100 rounded-pill fw-bold py-2 custom-btn" style={{ '--hover-color': service.color }}>
                    Book Project
                  </Link>
                </div>

              </div>
            </div>
          ))}
        </div>
      </div>

      {/* --- CUSTOM CSS --- */}
      <style>{`
        .service-card {
          transition: transform 0.4s ease, box-shadow 0.4s ease;
        }

        .service-card:hover {
          transform: translateY(-10px);
          box-shadow: 0 25px 50px rgba(0,0,0,0.15) !important;
        }

        .img-zoom {
          transition: transform 0.6s ease;
        }

        .service-card:hover .img-zoom {
          transform: scale(1.1);
        }

        .custom-btn {
          border: 2px solid #eee;
          transition: 0.3s;
        }

        .custom-btn:hover {
          background-color: var(--hover-color) !important;
          color: white !important;
          border-color: transparent !important;
        }
      `}</style>
    </div>
  );
}

export default Services;
